    // Lives
    ctx.textAlign = 'right';
    let livesText = '❤️'.repeat(lives);
    ctx.fillText(livesText, canvas.width - 15, 30);

    // Combo
    if (combo >= 3) {
        ctx.textAlign = 'center';
        ctx.font = 'bold 16px Arial';
        ctx.fillStyle = `hsl(${(combo * 30) % 360}, 100%, 60%)`;
        ctx.fillText(`连击 ×${combo}`, canvas.width / 2, 52);
    }

    // Ball count
    if (balls.length > 1) {
        ctx.textAlign = 'left';
        ctx.font = 'bold 14px Arial';
        ctx.fillStyle = '#ffee00';
        ctx.fillText(`🔮 球数: ${balls.length}`, 15, 52);
    }

    // Floating texts
    floatingTexts.forEach(t => {
        ctx.globalAlpha = t.alpha;
        ctx.font = 'bold 18px Arial';
        ctx.textAlign = 'center';
        ctx.fillStyle = t.color;
        ctx.fillText(t.text, t.x, t.y);
    });
    ctx.globalAlpha = 1;
}

function drawStartScreen() {
    drawStars();

    // Title
    ctx.save();
    let time = Date.now() / 1000;

    ctx.shadowBlur = 30;
    ctx.shadowColor = '#00f7ff';
    ctx.fillStyle = '#00f7ff';
    ctx.font = 'bold 52px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('弹球打砖块', canvas.width / 2, canvas.height / 2 - 100);
    ctx.shadowBlur = 0;

    // Subtitle
    ctx.fillStyle = '#ffee00';
    ctx.font = 'bold 28px Arial';
    ctx.fillText('🔮 双倍球道具版 🔮', canvas.width / 2, canvas.height / 2 - 50);

    // Instructions
    ctx.fillStyle = '#aaa';
    ctx.font = '18px Arial';
    ctx.fillText('鼠标/方向键 控制挡板', canvas.width / 2, canvas.height / 2 + 20);
    ctx.fillText('接住金色 ×2 道具可以让球分裂！', canvas.width / 2, canvas.height / 2 + 50);

    // Start button
    let pulseAlpha = 0.5 + Math.sin(time * 3) * 0.3;
    ctx.fillStyle = `rgba(0, 247, 255, ${pulseAlpha})`;
    ctx.font = 'bold 24px Arial';
    ctx.fillText('点击或按空格开始游戏', canvas.width / 2, canvas.height / 2 + 120);

    // Animated balls
    for (let i = 0; i < 5; i++) {
        let bx = canvas.width / 2 + Math.cos(time * 2 + i * 1.2) * 200;
        let by = canvas.height / 2 + Math.sin(time * 2 + i * 1.2) * 80 + 30;
        ctx.beginPath();
        ctx.arc(bx, by, 6, 0, Math.PI * 2);
        ctx.fillStyle = ['#ff006e', '#ffee00', '#00f7ff', '#9b5de5', '#00f5d4'][i];
        ctx.shadowBlur = 10;
        ctx.shadowColor = ctx.fillStyle;
        ctx.fill();
    }
    ctx.shadowBlur = 0;

    ctx.restore();
}

function drawGameOverScreen() {
    drawStars();

    ctx.fillStyle = 'rgba(0, 0, 0, 0.7)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.shadowBlur = 20;
    ctx.shadowColor = '#ff006e';
    ctx.fillStyle = '#ff006e';
    ctx.font = 'bold 48px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('游戏结束', canvas.width / 2, canvas.height / 2 - 60);
    ctx.shadowBlur = 0;

    ctx.fillStyle = '#fff';
    ctx.font = 'bold 28px Arial';
    ctx.fillText(`最终得分: ${score}`, canvas.width / 2, canvas.height / 2);

    ctx.fillStyle = '#ffbe0b';
    ctx.font = '20px Arial';
    ctx.fillText(`最大连击: ${maxCombo}`, canvas.width / 2, canvas.height / 2 + 40);
    ctx.fillText(`到达关卡: ${level}`, canvas.width / 2, canvas.height / 2 + 70);

    let time = Date.now() / 1000;
    let pulseAlpha = 0.5 + Math.sin(time * 3) * 0.3;
    ctx.fillStyle = `rgba(255, 255, 255, ${pulseAlpha})`;
    ctx.font = '22px Arial';
    ctx.fillText('点击或按空格重新开始', canvas.width / 2, canvas.height / 2 + 130);
}

function drawWinScreen() {
    drawStars();

    ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    let time = Date.now() / 1000;
    ctx.shadowBlur = 30;
    ctx.shadowColor = '#ffee00';
    ctx.fillStyle = '#ffee00';
    ctx.font = 'bold 52px Arial';
    ctx.textAlign = 'center';
    ctx.fillText('🎉 恭喜通关！ 🎉', canvas.width / 2, canvas.height / 2 - 60);
    ctx.shadowBlur = 0;

    ctx.fillStyle = '#fff';
    ctx.font = 'bold 28px Arial';
    ctx.fillText(`总得分: ${score}`, canvas.width / 2, canvas.height / 2);

    ctx.fillStyle = '#00f7ff';
    ctx.font = '20px Arial';
    ctx.fillText(`最大连击: ${maxCombo}`, canvas.width / 2, canvas.height / 2 + 40);

    let pulseAlpha = 0.5 + Math.sin(time * 3) * 0.3;
    ctx.fillStyle = `rgba(255, 255, 255, ${pulseAlpha})`;
    ctx.font = '22px Arial';
    ctx.fillText('点击或按空格重新开始', canvas.width / 2, canvas.height / 2 + 110);

    // Celebration particles
    if (Math.random() < 0.3) {
        createParticles(
            Math.random() * canvas.width,
            Math.random() * canvas.height / 2,
            ['#ff006e', '#ffee00', '#00f7ff', '#9b5de5', '#00f5d4'][Math.floor(Math.random() * 5)],
            3
        );
    }
}

function adjustBrightness(hex, amount) {
    let r = parseInt(hex.slice(1, 3), 16) + amount;
    let g = parseInt(hex.slice(3, 5), 16) + amount;
    let b = parseInt(hex.slice(5, 7), 16) + amount;
    r = Math.max(0, Math.min(255, r));
    g = Math.max(0, Math.min(255, g));
    b = Math.max(0, Math.min(255, b));
    return `rgb(${r},${g},${b})`;
}

// Main draw
function draw() {
    ctx.save();

    // Screen shake
    if (shakeTimer > 0) {
        let sx = (Math.random() - 0.5) * shakeIntensity;
        let sy = (Math.random() - 0.5) * shakeIntensity;
        ctx.translate(sx, sy);
    }

    // Clear
    ctx.fillStyle = '#0a0a2e';
    ctx.fillRect(-10, -10, canvas.width + 20, canvas.height + 20);

    if (gameState === 'start') {
        drawStartScreen();
    } else if (gameState === 'playing') {
        drawStars();
        drawBricks();
        drawPaddle();
        balls.forEach(ball => ball.draw());
        powerUps.forEach(p => p.draw());
        drawParticles();
        drawUI();
    } else if (gameState === 'gameover') {
        drawBricks();
        drawPaddle();
        drawParticles();
        drawGameOverScreen();
    } else if (gameState === 'win') {
        drawParticles();
        drawWinScreen();
    }

    ctx.restore();
}

// Game loop
function gameLoop() {
    update();
    draw();
    requestAnimationFrame(gameLoop);
}

// Polyfill for roundRect
if (!CanvasRenderingContext2D.prototype.roundRect) {
    CanvasRenderingContext2D.prototype.roundRect = function(x, y, w, h, r) {
        if (typeof r === 'number') r = { tl: r, tr: r, br: r, bl: r };
        else {
            r = Object.assign({ tl: 0, tr: 0, br: 0, bl: 0 }, r);
        }
        let radius = typeof r === 'object' ? r.tl : r;
        this.moveTo(x + radius, y);
        this.lineTo(x + w - radius, y);
        this.quadraticCurveTo(x + w, y, x + w, y + radius);
        this.lineTo(x + w, y + h - radius);
        this.quadraticCurveTo(x + w, y + h, x + w - radius, y + h);
        this.lineTo(x + radius, y + h);
        this.quadraticCurveTo(x, y + h, x, y + h - radius);
        this.lineTo(x, y + radius);
        this.quadraticCurveTo(x, y, x + radius, y);
        this.closePath();
    };
}

createBricks();
gameLoop();
